patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..6eb67fc0bbe4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -6821,6 +6821,7 @@ static Instruction *foldReductionIdiom(ICmpInst &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   bool Changed = false;
   const SimplifyQuery Q = SQ.getWithInstruction(&I);
@@ -6849,8 +6850,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
       if (Value *V = dyn_castNegVal(SelectTrue)) {
         if (V == SelectFalse)
           return CmpInst::Create(Instruction::ICmp, I.getPredicate(), V, Op1);
-      }
-      else if (Value *V = dyn_castNegVal(SelectFalse)) {
+      } else if (Value *V = dyn_castNegVal(SelectFalse)) {
         if (V == SelectTrue)
           return CmpInst::Create(Instruction::ICmp, I.getPredicate(), V, Op1);
       }
@@ -7021,6 +7021,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {

     // ~X < ~Y --> Y < X
     // ~X < C -->  X > ~C
+    // (~X ^ Y) < ~X --> X < (X ^ Y)   (generalized via (~X ^ Y) == ~(X ^ Y))
     if (match(Op0, m_Not(m_Value(X)))) {
       if (match(Op1, m_Not(m_Value(Y))))
         return new ICmpInst(I.getPredicate(), Y, X);
@@ -7031,6 +7032,14 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
                             ConstantInt::get(Op1->getType(), ~(*C)));
     }

+    if (match(Op1, m_Not(m_Value(X)))) {
+      if (match(Op0, m_Xor(m_Specific(Op1), m_Value(Y))) ||
+          match(Op0, m_Xor(m_Value(Y), m_Specific(Op1)))) {
+        Value *Xor = Builder.CreateXor(X, Y);
+        return new ICmpInst(I.getPredicate(), X, Xor);
+      }
+    }
+
     Instruction *AddI = nullptr;
     if (match(&I, m_UAddWithOverflow(m_Value(X), m_Value(Y),
                                      m_Instruction(AddI))) &&
@@ -7135,6 +7144,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Fold fcmp ([us]itofp x, cst) if possible.
 Instruction *InstCombinerImpl::foldFCmpIntToFPConst(FCmpInst &I,
                                                     Instruction *LHSI,

